import React from "react";

const skills = [
  { name: "HTML", emoji: "🌐" },
  { name: "CSS", emoji: "🎨" },
  { name: "JavaScript", emoji: "⚡" },
  { name: "TypeScript", emoji: "🛠️" },
  { name: "React", emoji: "⚛️" },
  { name: "React Native", emoji: "📱" },
  { name: "Django", emoji: "🐍" },
  { name: "Python", emoji: "🐍" },
  { name: "Azure", emoji: "☁️" },
  { name: "Share Hosting", emoji: "📡" },
  { name: "Digital Ocean", emoji: "🌊" },
  { name: "Mac", emoji: "🍏" },
  { name: "Windows", emoji: "🖥️" },
  { name: "Linux", emoji: "🐧" }
];

export default function Skills() {
  return (
    <section className="bg-gray-900 text-white py-10">
      <div className="container mx-auto text-center">
        <h2 className="text-4xl font-bold mb-6">💻 My Skills</h2>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6 px-6">
          {skills.map((skill, index) => (
            <div
              key={index}
              className="bg-gray-800 p-4 rounded-lg shadow-lg flex items-center justify-center gap-3 text-xl font-semibold transition transform hover:scale-105 hover:bg-gray-700"
            >
              <span className="text-2xl">{skill.emoji}</span>
              <span>{skill.name}</span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
